{"path": "/home/teacherchris37/frontend/src/components/rewards/TierBadge.tsx", "content": "import { Medal, Award, Crown, Diamond } from 'lucide-react';
import type { TierInfo } from '../../lib/api';

interface TierBadgeProps {
  tier: TierInfo | string;
  size?: 'sm' | 'md' | 'lg';
  showLabel?: boolean;
}

const tierConfig: Record<string, {
  icon: typeof Medal;
  gradient: string;
  textColor: string;
  bgColor: string;
  label: string;
}> = {
  Bronze: {
    icon: Medal,
    gradient: 'from-amber-700 to-amber-600',
    textColor: 'text-amber-700',
    bgColor: 'bg-amber-50',
    label: 'Bronze',
  },
  Silver: {
    icon: Award,
    gradient: 'from-gray-400 to-gray-300',
    textColor: 'text-gray-600',
    bgColor: 'bg-gray-50',
    label: 'Silver',
  },
  Gold: {
    icon: Crown,
    gradient: 'from-yellow-400 to-yellow-300',
    textColor: 'text-yellow-700',
    bgColor: 'bg-yellow-50',
    label: 'Gold',
  },
  Platinum: {
    icon: Diamond,
    gradient: 'from-purple-500 to-pink-400',
    textColor: 'text-purple-700',
    bgColor: 'bg-purple-50',
    label: 'Platinum',
  },
};

const sizeConfig = {
  sm: {
    container: 'w-8 h-8',
    icon: 'w-4 h-4',
    text: 'text-xs',
    badge: 'px-2 py-0.5 text-xs',
  },
  md: {
    container: 'w-12 h-12',
    icon: 'w-6 h-6',
    text: 'text-sm',
    badge: 'px-3 py-1 text-sm',
  },
  lg: {
    container: 'w-16 h-16',
    icon: 'w-8 h-8',
    text: 'text-base',
    badge: 'px-4 py-1.5 text-base',
  },
};

export function TierBadge({ tier, size = 'md', showLabel = true }: TierBadgeProps) {
  const tierName = typeof tier === 'string' ? tier : tier.name;
  const config = tierConfig[tierName] || tierConfig.Bronze;
  const Icon = config.icon;
  const sizes = sizeConfig[size];

  return (
    <div className="flex items-center gap-2">
      <div className={`${sizes.container} rounded-full bg-gradient-to-br ${config.gradient} flex items-center justify-center shadow-lg`}>
        <Icon className={`${sizes.icon} text-white`} />
      </div>
      {showLabel && (
        <span className={`font-semibold ${config.textColor} ${sizes.text}`}>
          {config.label}
        </span>
      )}
    </div>
  );
}

export function TierBadgePill({ tier, size = 'md' }: TierBadgeProps) {
  const tierName = typeof tier === 'string' ? tier : tier.name;
  const config = tierConfig[tierName] || tierConfig.Bronze;
  const Icon = config.icon;
  const sizes = sizeConfig[size];

  return (
    <div className={`inline-flex items-center gap-1.5 ${sizes.badge} rounded-full ${config.bgColor} ${config.textColor} font-medium`}>
      <Icon className="w-3.5 h-3.5" />
      <span>{config.label}</span>
    </div>
  );
}

export default TierBadge;
"}

{"path": "/home/teacherchris37/frontend/src/components/rewards/CoinBalance.tsx", "content": "import { Coins, TrendingUp, TrendingDown } from 'lucide-react';

interface CoinBalanceProps {
  balance: number;
  showValue?: boolean;
  size?: 'sm' | 'md' | 'lg';
  change?: number;
}

const sizeConfig = {
  sm: {
    container: 'px-3 py-1.5',
    icon: 'w-4 h-4',
    balance: 'text-base',
    value: 'text-xs',
    change: 'text-xs',
  },
  md: {
    container: 'px-4 py-2',
    icon: 'w-5 h-5',
    balance: 'text-xl',
    value: 'text-sm',
    change: 'text-sm',
  },
  lg: {
    container: 'px-6 py-4',
    icon: 'w-8 h-8',
    balance: 'text-3xl',
    value: 'text-base',
    change: 'text-base',
  },
};

export function CoinBalance({ balance, showValue = true, size = 'md', change }: CoinBalanceProps) {
  const sizes = sizeConfig[size];
  const zarValue = (balance * 0.1).toFixed(2);

  return (
    <div className={`inline-flex items-center gap-3 bg-gradient-to-r from-primary-50 to-primary-100 border border-primary-200 rounded-xl ${sizes.container}`}>
      <div className="relative">
        <Coins className={`${sizes.icon} text-primary-600`} />
        <div className="absolute -top-1 -right-1 w-2 h-2 bg-primary-400 rounded-full animate-pulse" />
      </div>
      <div>
        <div className="flex items-center gap-2">
          <span className={`font-bold text-secondary-600 ${sizes.balance}`}>
            {balance.toLocaleString()}
          </span>
          {change !== undefined && change !== 0 && (
            <span className={`inline-flex items-center gap-0.5 ${sizes.change} ${change > 0 ? 'text-green-600' : 'text-red-600'}`}>
              {change > 0 ? <TrendingUp className="w-3 h-3" /> : <TrendingDown className="w-3 h-3" />}
              {Math.abs(change)}
            </span>
          )}
        </div>
        {showValue && (
          <p className={`text-secondary-400 ${sizes.value}`}>
            = R{zarValue}
          </p>
        )}
      </div>
    </div>
  );
}

export function MiniCoinBalance({ balance }: { balance: number }) {
  return (
    <div className="flex items-center gap-1.5 text-sm">
      <Coins className="w-4 h-4 text-primary-600" />
      <span className="font-semibold text-secondary-600">{balance.toLocaleString()}</span>
      <span className="text-secondary-400 text-xs">coins</span>
    </div>
  );
}

export default CoinBalance;
"}

{"path": "/home/teacherchris37/frontend/src/components/rewards/ReferralCard.tsx", "content": "import { useState } from 'react';
import { Copy, Check, Share2, Users, Gift } from 'lucide-react';

interface ReferralCardProps {
  referralCode: string;
  referralLink: string;
  successfulReferrals?: number;
  coinsPerReferral?: number;
  compact?: boolean;
}

export function ReferralCard({
  referralCode,
  referralLink,
  successfulReferrals = 0,
  coinsPerReferral = 50,
  compact = false,
}: ReferralCardProps) {
  const [copied, setCopied] = useState(false);

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(referralLink);
      setCopied(true);
      setTimeout(() => setCopied(false), 2000);
    } catch (err) {
      console.error('Failed to copy:', err);
    }
  };

  const handleShare = async () => {
    const shareData = {
      title: 'Join iHhashi - Get R25 worth of Hashi Coins!',
      text: `Use my referral code ${referralCode} to join iHhashi and get ${coinsPerReferral} Hashi Coins (R25 value)! 🎉`,
      url: referralLink,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.error('Share failed:', err);
      }
    } else {
      handleCopy();
    }
  };

  if (compact) {
    return (
      <div className="bg-white rounded-xl p-4 shadow-card border border-gray-100">
        <div className="flex items-center justify-between mb-2">
          <span className="text-sm text-gray-500">Your Referral Code</span>
          <div className="flex items-center gap-1 text-sm text-primary-600">
            <Users className="w-4 h-4" />
            <span>{successfulReferrals} referrals</span>
          </div>
        </div>
        <div className="flex items-center gap-2">
          <div className="flex-1 bg-gray-50 rounded-lg px-3 py-2 font-mono text-lg font-semibold text-secondary-600 tracking-wider">
            {referralCode}
          </div>
          <button
            onClick={handleCopy}
            className="p-2 bg-primary-100 text-primary-700 rounded-lg hover:bg-primary-200 transition-colors"
            title="Copy referral link"
          >
